// ============================================================
// N8N PII Scrubber + Parser (espelho de backend/app/services/pii.py)
// LGPD art. 6o VIII - prevencao: falso positivo aceito, falso
// negativo NAO. Antes de chamar LLM externo, scrubber garante
// que CPF/RG/CNPJ/cartao/etc NAO vao pra OpenCode-Go.
// ============================================================
const item = $input.item.json;
const body = item.body || {};

// Extrai mensagem do payload Evolution (formato canonico + fallback)
const rawText = (
  (body.message && (body.message.text || body.message.conversation)) ||
  body.text ||
  body.raw ||
  ''
).toString();

const sender = body.sender || body.from || 'unknown';
const instance = body.instance || 'cartorio-2notas-uberlandia';

// Regex calibrado (espelho de app/services/pii.py - P0 LGPD fix 2026-06-23).
// Ordem importa: mais especifico primeiro.
const patterns = [
  { label: 'email',       re: /\b[\w.+-]+@[\w-]+\.[\w.-]+\b/g },
  { label: 'data',        re: /\b\d{2}[\/\-\.]\d{2}[\/\-\.]\d{4}\b|\b\d{4}-\d{2}-\d{2}\b/g },
  { label: 'placa',       re: /\b[A-Z]{3}-?\d[A-Z]\d{2}\b|\b[A-Z]{3}-?\d{4}\b/g },
  { label: 'cnpj',        re: /\b\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2}\b/g },
  { label: 'cpf',         re: /\b\d{3}\.?\d{3}\.\d{3}-?\d{2}\b/g },
  { label: 'pis',         re: /\b\d{3}\.\d{5}\.\d{3}\b/g },
  { label: 'rg',          re: /\b\d{1,2}\.\d{3}\.?\d{3}-?[\dxX]\b/g },
  { label: 'titulo',      re: /\b\d{4}\s?\d{4}\s?\d{4}\b/g },
  { label: 'phone_br',    re: /(?:\+?55\s?)?\(?\d{2}\)?\s?9?\d{4}[\s-]?\d{4}/g },
  { label: 'cep',         re: /\b\d{5}-?\d{3}\b/g },
  { label: 'cartao',      re: /\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b|\b\d{4}[\s-]?\d{6}[\s-]?\d{5}\b/g }
];

let scrubbed = rawText;
const findings = {};
let redactionCount = 0;

for (const { label, re } of patterns) {
  const matches = scrubbed.match(re);
  if (matches && matches.length) {
    findings[label] = matches.length;
    redactionCount += matches.length;
    scrubbed = scrubbed.replace(re, `[${label.toUpperCase()}_REDACTED]`);
  }
}

// Bloqueio automatico: se QUALQUER PII detectado, NAO envia pro LLM
// (handoff humano obrigatorio - LGPD art. 7o I + 46).
const blocked = redactionCount > 0;

return [{
  json: {
    sender,
    instance,
    raw_length: rawText.length,
    raw_excerpt: rawText.substring(0, 200),
    scrubbed,
    findings,
    redaction_count: redactionCount,
    blocked,
    consent_granted: !blocked, // LGPD: so chama LLM se NAO bloqueado
    timestamp: new Date().toISOString()
  }
}];

