// ============================================================
// Formata resposta do LLM + adiciona metadata LGPD-safe
// ============================================================
const llm = $input.item.json;
const scrub = $('PII Scrubber (local, LGPD)').item.json;

const llmOk = llm.status === 'ok' && llm.response;
const resposta = llmOk
  ? llm.response
  : 'Desculpe, nao consegui processar sua mensagem agora. Um atendente humano ira retornar em instantes.';

return [{
  json: {
    status: llmOk ? 'ok' : 'llm_error',
    response: resposta,
    sender: scrub.sender,
    pii_blocked: scrub.blocked,
    pii_findings: scrub.findings,
    pii_redaction_count: scrub.redaction_count,
    model: llm.model || 'deepseek-v4-flash',
    tokens_in: llm.tokens_in || null,
    tokens_out: llm.tokens_out || null,
    latency_ms: llm.latency_ms || null,
    needs_human_handoff: !llmOk || scrub.blocked,
    provider: llm.config ? llm.config.provider : 'opencode_go',
    timestamp: scrub.timestamp
  }
}];

// ============================================================
// Resposta quando PII detectado: BLOQUEIA LLM, escuta para handoff
// humano. NUNCA envia dado sensivel pra OpenCode-Go.
// ============================================================
const scrub = $input.item.json;

return [{
  json: {
    status: 'pii_blocked',
    response: 'Detectei dados pessoais na sua mensagem (CPF, RG ou documento). Por questao de seguranca e conformidade com a LGPD, vou transferir seu atendimento para um escrevente humano. Por favor, aguarde alguns instantes.',
    sender: scrub.sender,
    pii_blocked: true,
    pii_findings: scrub.findings,
    pii_redaction_count: scrub.redaction_count,
    needs_human_handoff: true,
    model: null,
    tokens_in: null,
    tokens_out: null,
    latency_ms: null,
    provider: 'handoff_humano',
    timestamp: scrub.timestamp
  }
}];
